16	
17	// memStore is an in-memory tokenstore.Store for tests. Avoids pulling
18	// the keyring backend into tokenmanager's test surface.
19	type memStore struct {
20		data map[string]tokens.TokenSet
21	}
22	
23	func newMemStore() *memStore { return &memStore{data: map[string]tokens.TokenSet{}} }
24	
25	func (s *memStore) SaveTokens(profile string, t tokens.TokenSet) error {
26		s.data[profile] = t
27		return nil
28	}
29	
30	func (s *memStore) LoadTokens(profile string) (tokens.TokenSet, error) {
31		t, ok := s.data[profile]
32		if !ok {
33			return tokens.TokenSet{}, tokenstore.ErrNotFound
34		}
35		return t, nil
36	}
37	
38	func (s *memStore) DeleteTokens(profile string) error {
39		delete(s.data, profile)
