		{"empty Path", func(c *Client) { c.Path = "" }, "Path"},
	}
	for _, tc := range missing {
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			c := base()
			tc.mutate(c)
			_, err := New(c)
			if err == nil {
				t.Fatalf("New(%s missing) = nil, want error", tc.want)
			}
			if !strings.Contains(err.Error(), tc.want) {
